import { useState } from 'react';
import { toast } from 'react-toastify';
import advisoryService from '../api/advisoryService';

function AdvisoryForm({ onAdvisoryCreated }) {
  const [formData, setFormData] = useState({
    soilType: '',
    season: '',
    waterLevel: '',
  });
  const [loading, setLoading] = useState(false);

  const { soilType, season, waterLevel } = formData;

  const onChange = (e) => {
    setFormData((prevState) => ({
      ...prevState,
      [e.target.name]: e.target.value,
    }));
  };

  const onSubmit = async (e) => {
    e.preventDefault();

    try {
      setLoading(true);
      
      if (!soilType || !season || !waterLevel) {
        toast.error('Please fill all fields');
        setLoading(false);
        return;
      }

      const user = JSON.parse(localStorage.getItem('user'));
      
      if (!user) {
        toast.error('You must be logged in');
        setLoading(false);
        return;
      }

      const newAdvisory = await advisoryService.createAdvisory(
        formData,
        user.token
      );

      setFormData({
        soilType: '',
        season: '',
        waterLevel: '',
      });

      if (onAdvisoryCreated) {
        onAdvisoryCreated(newAdvisory);
      }

      toast.success('Advisory created successfully');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Something went wrong');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-md">
      <h2 className="text-2xl font-bold text-green-700 mb-6">
        Get Crop Recommendations
      </h2>
      
      <form onSubmit={onSubmit}>
        <div className="form-group">
          <label className="block text-gray-700 mb-2" htmlFor="soilType">
            Soil Type
          </label>
          <select
            className="form-control"
            id="soilType"
            name="soilType"
            value={soilType}
            onChange={onChange}
            required
          >
            <option value="">Select soil type</option>
            <option value="clay">Clay</option>
            <option value="sandy">Sandy</option>
            <option value="loamy">Loamy</option>
            <option value="silty">Silty</option>
            <option value="peaty">Peaty</option>
            <option value="chalky">Chalky</option>
          </select>
        </div>

        <div className="form-group">
          <label className="block text-gray-700 mb-2" htmlFor="season">
            Season
          </label>
          <select
            className="form-control"
            id="season"
            name="season"
            value={season}
            onChange={onChange}
            required
          >
            <option value="">Select season</option>
            <option value="summer">Summer</option>
            <option value="winter">Winter</option>
            <option value="rainy">Rainy</option>
            <option value="spring">Spring</option>
          </select>
        </div>

        <div className="form-group">
          <label className="block text-gray-700 mb-2" htmlFor="waterLevel">
            Water Availability
          </label>
          <select
            className="form-control"
            id="waterLevel"
            name="waterLevel"
            value={waterLevel}
            onChange={onChange}
            required
          >
            <option value="">Select water level</option>
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
          </select>
        </div>

        <button
          type="submit"
          className="btn btn-primary w-full mt-4"
          disabled={loading}
        >
          {loading ? 'Getting recommendations...' : 'Get Recommendations'}
        </button>
      </form>
    </div>
  );
}

export default AdvisoryForm;
